import { notFound } from "next/navigation";
import Image from "next/image";
import Link from "next/link";
import { ArrowLeft, Calendar, User, Tag } from "lucide-react";
import { blogPosts } from "../page";

export function generateMetadata({ params }: { params: { slug: string } }) {
  const post = blogPosts.find(p => p.id === params.slug);
  if (!post) return { title: "Post Not Found" };
  return {
    title: `${post.title} | Dilip Bhandge Blog`,
    description: post.excerpt,
  };
}

export default function BlogPostPage({ params }: { params: { slug: string } }) {
  const post = blogPosts.find(p => p.id === params.slug);

  if (!post) {
    notFound();
  }

  return (
    <main className="min-h-screen bg-white pt-24 pb-20">
      <article className="mx-auto max-w-4xl px-6 md:px-12 mt-8">
        <Link href="/blog" className="inline-flex items-center text-sm font-medium text-gray-500 hover:text-primary mb-8 transition-colors">
          <ArrowLeft size={16} className="mr-2" /> Back to all articles
        </Link>

        <div className="mb-10 text-center">
          <span className="inline-flex items-center px-4 py-2 bg-slate-100 rounded-full text-sm font-semibold text-primary mb-6">
            <Tag size={16} className="mr-2" /> {post.category}
          </span>
          <h1 className="text-4xl md:text-5xl lg:text-6xl font-display font-bold text-gray-900 mb-8 leading-tight">
            {post.title}
          </h1>
          <div className="flex items-center justify-center gap-6 text-sm text-gray-500">
            <span className="flex items-center"><User size={16} className="mr-2" /> By {post.author}</span>
            <span className="flex items-center"><Calendar size={16} className="mr-2" /> {post.date}</span>
          </div>
        </div>

        <div className="relative aspect-video w-full rounded-3xl overflow-hidden shadow-xl mb-12">
           <Image src={post.image} alt={post.title} fill className="object-cover" priority />
        </div>

        <div className="prose prose-lg max-w-none text-gray-600">
          <p className="lead text-xl text-gray-800 font-medium mb-8">
            {post.excerpt}
          </p>
          <p>
            Real estate in Maharashtra is continuously evolving, and localities like Wakad are at the forefront of this transformation. With rapid infrastructure development, proximity to major IT hubs like Hinjewadi, and excellent connectivity to Mumbai via the Expressway, property investments here are yielding significant returns.
          </p>
          <h2>Infrastructure Development</h2>
          <p>
            The upcoming metro line and ring road projects are set to drastically reduce commute times, making the area even more attractive to professionals and families alike. Builders are focusing on delivering holistic townships with world-class amenities to cater to the modern home buyer.
          </p>
          <blockquote>
            "An investment in the right locality today is the foundation for generational wealth tomorrow." - Dilip Bhandge
          </blockquote>
          <h2>Future Projections</h2>
          <p>
            Market analysts predict a steady capital appreciation of 8-10% annually in emerging corridors. For NRIs and local investors, early entry into these under-construction projects provides the dual benefit of lower entry prices and maximum ROI upon project completion.
          </p>

          <div className="mt-16 bg-primary/5 p-8 rounded-2xl border border-primary/10 text-center">
             <h3 className="text-2xl font-bold font-display text-gray-900 mb-4 mt-0">Ready to invest in {post.category === "NRI Services" ? "India" : "Wakad"}?</h3>
             <p className="mb-6">Contact our team for a personalized property consultation.</p>
             <Link href="/contact" className="inline-flex items-center justify-center px-8 py-3 bg-primary text-white font-medium rounded-lg hover:bg-primary/90 transition-colors">
               Book a Consultation
             </Link>
          </div>
        </div>

      </article>
    </main>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Button } from "@/components/ui/Button";
import { Menu, X, PhoneCall } from "lucide-react";
import { cn } from "@/lib/utils";

export function Header() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const navLinks = [
    { name: "Home", href: "/" },
    { name: "Properties", href: "/properties" },
    { name: "About", href: "/about" },
    { name: "Services", href: "/services" },
    { name: "Contact", href: "/contact" },
  ];

  return (
    <header
      className={cn(
        "fixed left-0 top-0 z-50 w-full transition-all duration-300",
        isScrolled
          ? "bg-white/90 shadow-md backdrop-blur-md py-3"
          : "bg-transparent py-5"
      )}
    >
      <div className="mx-auto flex max-w-7xl items-center justify-between px-6 md:px-12">
        {/* Logo */}
        <Link href="/" className="flex items-center gap-2 z-50">
          <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary text-secondary font-bold text-xl">
            DB
          </div>
          <span
            className={cn(
              "font-display font-bold text-xl tracking-wide",
              isScrolled || isMobileMenuOpen ? "text-primary" : "text-white"
            )}
          >
            Dilip Bhandge
          </span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden md:flex items-center gap-8">
          <ul className="flex items-center gap-6">
            {navLinks.map((link) => (
              <li key={link.name}>
                <Link
                  href={link.href}
                  className={cn(
                    "text-sm font-medium transition-colors hover:text-secondary",
                    isScrolled ? "text-gray-700" : "text-gray-200"
                  )}
                >
                  {link.name}
                </Link>
              </li>
            ))}
          </ul>
          <a href="tel:+919876543210">
            <Button
              variant={isScrolled ? "default" : "outline"}
              className={cn(
                "rounded-full px-6",
                !isScrolled && "border-white text-white hover:bg-white/20"
              )}
            >
              <PhoneCall size={18} className="mr-2" /> Let's Talk
            </Button>
          </a>
        </nav>

        {/* Mobile Toggle */}
        <button
          className={cn(
            "md:hidden z-50 p-2",
            isScrolled || isMobileMenuOpen ? "text-gray-900" : "text-white"
          )}
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </div>

      {/* Mobile Menu */}
      <div
        className={cn(
          "fixed inset-0 z-40 flex flex-col items-center justify-center bg-white transition-transform duration-300 ease-in-out md:hidden",
          isMobileMenuOpen ? "translate-x-0" : "translate-x-full"
        )}
      >
        <ul className="flex flex-col items-center gap-8 text-2xl font-semibold text-primary font-display">
          {navLinks.map((link) => (
            <li key={link.name}>
              <Link
                href={link.href}
                onClick={() => setIsMobileMenuOpen(false)}
                className="hover:text-secondary transition-colors"
              >
                {link.name}
              </Link>
            </li>
          ))}
        </ul>
        <a href="tel:+919876543210" className="mt-12 w-full px-12">
          <Button className="w-full bg-secondary text-primary" size="lg">
            <PhoneCall size={20} className="mr-2" /> Call Now
          </Button>
        </a>
      </div>
    </header>
  );
}

import React from 'react';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@/lib/utils';
import { Loader2 } from 'lucide-react';

const buttonVariants = cva(
  'inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 min-h-[48px] px-6 py-2 touch-manipulation',
  {
    variants: {
      variant: {
        default: 'bg-[#0A2472] text-white hover:bg-[#081b56] active:scale-95 transition-all',
        destructive: 'bg-red-500 text-white hover:bg-red-600',
        outline: 'border border-[#0A2472] text-[#0A2472] bg-transparent hover:bg-[#0A2472]/10',
        secondary: 'bg-[#C6A43F] text-white hover:bg-[#a88a32]',
        ghost: 'hover:bg-accent hover:text-accent-foreground',
        link: 'text-primary underline-offset-4 hover:underline',
        glass: 'backdrop-blur-md bg-white/10 border border-white/20 text-white hover:bg-white/20',
      },
      size: {
        default: 'h-12 px-6 py-2',
        sm: 'h-10 rounded-md px-4',
        lg: 'h-14 rounded-md px-8 text-base',
        icon: 'h-12 w-12',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'default',
    },
  }
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
  isLoading?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, isLoading, children, ...props }, ref) => {
    return (
      <button
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        disabled={isLoading || props.disabled}
        {...props}
      >
        {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
        {children}
      </button>
    );
  }
);
Button.displayName = 'Button';

export { Button, buttonVariants };

import { PropertyCard } from "@/components/ui/PropertyCard";
import { properties } from "@/lib/constants";
import { ArrowRight, MapPin } from "lucide-react";
import Link from "next/link";
import { Button } from "@/components/ui/Button";

interface LocationPageProps {
  locationName: string;
  title: string;
  description: string;
  highlightText: string;
}

export function LocationPageTemplate({ locationName, title, description, highlightText }: LocationPageProps) {
  // Mock filtering properties based on location
  const filteredProperties = properties.filter(p => 
    p.location.toLowerCase().includes(locationName.toLowerCase().replace('pune', '').trim())
  );

  // For demonstration, if no match, just show all
  const displayedProperties = filteredProperties.length > 0 ? filteredProperties : properties;

  return (
    <main className="min-h-screen bg-slate-50 pt-24 pb-20">
      {/* Location Hero */}
      <section className="bg-primary pt-24 pb-16 px-6 text-center relative overflow-hidden">
        <div className="absolute inset-0 z-0 opacity-10">
          <div className="absolute inset-0 bg-black/60 z-10" />
            <img src="https://images.unsplash.com/photo-1512917774080-9991f1c4c750?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80" alt="Background" className="w-full h-full object-cover" />
        </div>
        <div className="relative z-10 max-w-4xl mx-auto">
          <div className="inline-flex items-center px-4 py-2 bg-secondary/20 text-secondary rounded-full text-sm font-semibold mb-6 backdrop-blur-sm border border-secondary/30">
             <MapPin size={16} className="mr-2" /> Local Area Guide
          </div>
          <h1 className="text-4xl md:text-5xl lg:text-6xl font-display font-bold text-white mb-6 leading-tight">
            {title}
          </h1>
          <p className="text-xl text-gray-300 mb-8 max-w-2xl mx-auto">
            {description}
          </p>
          <p className="text-lg text-secondary font-medium italic">
            {highlightText}
          </p>
        </div>
      </section>

      {/* Properties Grid */}
      <section className="mx-auto max-w-7xl px-6 md:px-12 py-20 -mt-10 relative z-20">
        <div className="bg-white rounded-3xl p-8 md:p-12 shadow-xl border border-gray-100 mb-12 flex flex-col md:flex-row justify-between items-center text-center md:text-left gap-6">
           <div>
             <h2 className="text-2xl font-bold font-display text-gray-900 mb-2">Find your perfect home in {locationName}</h2>
             <p className="text-gray-600">Showing {displayedProperties.length} verified premium properties in this locality.</p>
           </div>
           <Link href="/contact">
             <Button size="lg" className="bg-primary hover:bg-primary/90 text-white shadow-md">
                Get Expert Advice
             </Button>
           </Link>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {displayedProperties.map((prop) => (
            <PropertyCard key={prop.id} {...prop} />
          ))}
        </div>

        {displayedProperties.length === properties.length && (
           <div className="mt-12 text-center text-gray-500">
              <p>Currently showing popular properties across Pune. Contact us for exclusive listings in {locationName}.</p>
           </div>
        )}
      </section>

      {/* Area Highlights */}
      <section className="bg-white py-20 border-t border-gray-100">
         <div className="mx-auto max-w-7xl px-6 md:px-12 text-center">
            <h2 className="text-3xl md:text-4xl font-display font-bold text-gray-900 mb-12">Why Invest in {locationName}?</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
               <div className="p-6 rounded-2xl bg-slate-50 border border-slate-100">
                  <h3 className="text-xl font-bold text-primary mb-3">Excellent Connectivity</h3>
                  <p className="text-gray-600">Seamless access to major highways, IT parks, and upcoming metro lines ensuring reduced commute times for working professionals.</p>
               </div>
               <div className="p-6 rounded-2xl bg-slate-50 border border-slate-100">
                  <h3 className="text-xl font-bold text-primary mb-3">High Capital Appreciation</h3>
                  <p className="text-gray-600">Historically delivering strong year-on-year returns, making it a lucrative choice for both end-users and investors.</p>
               </div>
               <div className="p-6 rounded-2xl bg-slate-50 border border-slate-100">
                  <h3 className="text-xl font-bold text-primary mb-3">Social Infrastructure</h3>
                  <p className="text-gray-600">Surrounded by reputed international schools, multi-specialty hospitals, and premium shopping malls.</p>
               </div>
            </div>
         </div>
      </section>
    </main>
  );
}
